import android.webkit.*
import android.content.Context
import android.widget.Toast
import android.app.NotificationManager
import android.app.NotificationChannel
import android.os.Build
import androidx.core.app.NotificationCompat
import android.app.PendingIntent
import android.content.Intent
import android.graphics.BitmapFactory

class CustomWebView(context: Context) : WebView(context) {

    init {
        settings.javaScriptEnabled = true
        addJavascriptInterface(WebAppInterface(context), "Android")
    }

    private inner class WebAppInterface(private val mContext: Context) {

        @JavascriptInterface
        fun showToast(toast: String) {
            Toast.makeText(mContext, toast, Toast.LENGTH_SHORT).show()
        }

        @JavascriptInterface
        fun saveInLocalStorage(key: String, data: String) {
            val sharedPref = mContext.getSharedPreferences("APP_PREFERENCES", Context.MODE_PRIVATE)
            with(sharedPref.edit()) {
                putString(key, data)
                apply()
            }
        }

        @JavascriptInterface
        fun pushNotification() {
            val notificationManager = mContext.getSystemService(NotificationManager::class.java)
            val notificationId = 101
            val channelId = "channel-01"
            val channelName = "Channel Name"
            val notificationBuilder: NotificationCompat.Builder

            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                val importance = NotificationManager.IMPORTANCE_HIGH
                val channel = NotificationChannel(channelId, channelName, importance)
                notificationManager.createNotificationChannel(channel)
                notificationBuilder = NotificationCompat.Builder(mContext, channelId)
            } else {
                notificationBuilder = NotificationCompat.Builder(mContext)
            }

            val intent = Intent(mContext, MainActivity::class.java)
            val pendingIntent = PendingIntent.getActivity(mContext, 0, intent, 0)
            val icon = BitmapFactory.decodeResource(mContext.resources, R.drawable.ic_launcher)

            notificationBuilder.setAutoCancel(true)
                .setDefaults(NotificationCompat.DEFAULT_ALL)
                .setWhen(System.currentTimeMillis())
                .setSmallIcon(R.drawable.ic_launcher)
                .setLargeIcon(icon)
                .setContentTitle("Notification Title")
                .setContentIntent(pendingIntent)
                .setContentText("This is a test notification")
                .setDefaults(NotificationCompat.DEFAULT_ALL)

            notificationManager.notify(notificationId, notificationBuilder.build())
        }
        
        @JavascriptInterface
        fun openCamera() {
            val cameraIntent = Intent(android.provider.MediaStore.ACTION_IMAGE_CAPTURE)
            (mContext as Activity).startActivityForResult(cameraIntent, CAMERA_REQUEST_CODE)
        }
    }

    companion object {
        const val CAMERA_REQUEST_CODE = 100
    }
}